1	import { useState, useEffect } from 'react'
2	import type { TaskProgress } from '../data/progress'
3	
4	export function useProgress(intervalMs = 5000): TaskProgress[] {
5	  const [data, setData] = useState<TaskProgress[]>([])
6	
7	  useEffect(() => {
8	    const fetchProgress = async () => {
9	      try {
10	        const res = await fetch(`/api/progress?t=${Date.now()}`)
11	        if (res.ok) {
12	          setData(await res.json())
13	        }
14	      } catch {
15	        // silently retry next interval
16	      }
17	    }
18	
19	    fetchProgress()
20	    const id = setInterval(fetchProgress, intervalMs)
21	    return () => clearInterval(id)
22	  }, [intervalMs])
23	
24	  return data
25	}
26

